"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { getDashboardPathForRole } from "../../../lib/auth";
import AddRecordForm from "../../doctor/components/AddRecordForm";

export default function DoctorDashboard() {
  const [patientId, setPatientId] = useState("");
  const [patient, setPatient] = useState<any>(null);
  const router = useRouter();

  useEffect(() => {
    const stored = localStorage.getItem("user");

    if (!stored) {
      router.replace("/auth/login");
      return;
    }

    const user = JSON.parse(stored);

    // Only DOCTORs can access this dashboard
    if (user.role !== "DOCTOR") {
      const target = getDashboardPathForRole(user.role);
      router.replace(target);
    }
  }, []);

  const searchPatient = async () => {
    const res = await fetch(
      `http://localhost:5000/api/doctor/search?patientId=${patientId}`,
      {
        headers: {
          Authorization: `Bearer ${localStorage.getItem("token")}`,
        },
      }
    );

    const data = await res.json();
    setPatient(data);
  };

  return (
    <div className="space-y-6">
      <h1 className="text-xl font-bold mb-4">Doctor Dashboard</h1>

      {/* Patient Search Section */}
      <div className="bg-white p-4 rounded shadow mb-4">
        <h2 className="text-lg font-semibold mb-3">Search Patient</h2>
        <div className="flex flex-wrap gap-2 items-center">
          <input
            placeholder="Enter Patient ID"
            value={patientId}
            onChange={(e) => setPatientId(e.target.value)}
            className="border p-2 mr-2 flex-1 min-w-[200px]"
          />
          <button
            onClick={searchPatient}
            className="bg-blue-600 text-white px-4 py-2 rounded"
          >
            Search
          </button>
        </div>
      </div>

      {patient && (
        <div className="bg-white p-4 rounded shadow">
          <h3 className="text-md font-semibold mb-2">Patient Details</h3>
          <p>
            <strong>Name:</strong> {patient.name}
          </p>
          <p>
            <strong>Phone:</strong> {patient.phone}
          </p>
        </div>
      )}

      {/* Add Patient Record Section (from /app/doctor/add-record) */}
      <div className="bg-white p-4 rounded shadow">
        <h2 className="text-lg font-semibold mb-3">Add Medical Record</h2>
        <AddRecordForm />
      </div>
    </div>
  );
}